namespace sv_ec18d3d009654eb6a8144158274f6ed6.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// </summary>
public class ThemeService
{
    private ThemeMode _theme = ThemeMode.System;
    private string _accentColor = "#0d6efd";

    public ThemeMode Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@using sv_ec18d3d009654eb6a8144158274f6ed6.Services
@inject ThemeService ThemeSvc
@implements IDisposable

<span class="theme-indicator" style="color: @ThemeSvc.AccentColor;" title="Current theme">
    @GetThemeIcon() @ThemeSvc.Theme
</span>

@code {
    protected override void OnInitialized() => ThemeSvc.OnChange += OnThemeChanged;

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    private string GetThemeIcon() => ThemeSvc.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark  => "🌙",
        _               => "💻"
    };

    public void Dispose() => ThemeSvc.OnChange -= OnThemeChanged;
}

@using sv_ec18d3d009654eb6a8144158274f6ed6.Services
@inject ThemeService ThemeSvc

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme" title="Toggle theme">
    @GetIcon()
</button>

@code {
    private void CycleTheme()
    {
        ThemeSvc.Theme = ThemeSvc.Theme switch
        {
            ThemeMode.Light  => ThemeMode.Dark,
            ThemeMode.Dark   => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _ => ThemeMode.Light
        };
    }

    private string GetIcon() => ThemeSvc.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark  => "🌙",
        _               => "💻"
    };
}

@page "/settings"
@rendermode InteractiveServer
@using sv_ec18d3d009654eb6a8144158274f6ed6.Services
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label fw-bold">Theme Mode</label>
    <div class="btn-group d-block" role="group">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            var isActive = ThemeSvc.Theme == mode;
            <button class="btn @(isActive ? "btn-primary" : "btn-outline-primary")"
                    @onclick="() => ThemeSvc.Theme = mode">
                @mode
            </button>
        }
    </div>
</div>

<div class="mb-3">
    <label class="form-label fw-bold" for="accent">Accent Color</label>
    <input id="accent" type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnAccentChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @ThemeSvc.AccentColor !important;">
    <strong>Preview:</strong> Theme is <em>@ThemeSvc.Theme</em>, accent is
    <span style="color: @ThemeSvc.AccentColor;">@ThemeSvc.AccentColor</span>.
</div>

@code {
    protected override void OnInitialized() => ThemeSvc.OnChange += OnThemeChanged;

    private void OnAccentChanged(ChangeEventArgs e)
    {
        ThemeSvc.AccentColor = e.Value?.ToString() ?? "#0d6efd";
    }

    private void OnThemeChanged() => InvokeAsync(StateHasChanged);

    public void Dispose() => ThemeSvc.OnChange -= OnThemeChanged;
}

